import json
import re
import math

# Load data
with open(locals()['var_function-call-4035037722038278457'], 'r') as f:
    mutation_data = json.load(f)

with open(locals()['var_function-call-15857983146014450064'], 'r') as f:
    clinical_data = json.load(f)

# Create set of mutated barcodes
mutated_barcodes = set()
for entry in mutation_data:
    bc = entry.get('ParticipantBarcode')
    if bc:
        mutated_barcodes.add(bc)

# Process clinical data
# Counts structure: { hist_type: {'Yes': 0, 'No': 0} }
counts = {}
barcode_pattern = re.compile(r"(TCGA-[A-Z0-9]{2}-[A-Z0-9]{4})")

for entry in clinical_data:
    desc = entry.get('Patient_description', '')
    hist_type = entry.get('histological_type')

    # Extract barcode
    match = barcode_pattern.search(desc)
    if match:
        barcode = match.group(1)

        # Check mutation status
        has_mutation = barcode in mutated_barcodes

        if hist_type and hist_type != 'None':
            if hist_type not in counts:
                counts[hist_type] = {'Yes': 0, 'No': 0}

            if has_mutation:
                counts[hist_type]['Yes'] += 1
            else:
                counts[hist_type]['No'] += 1

# Filter out categories with marginal totals <= 10
filtered_counts = {}
excluded_types = []

for hist_type, val in counts.items():
    total = val['Yes'] + val['No']
    if total > 10:
        filtered_counts[hist_type] = val
    else:
        excluded_types.append(hist_type)

# Calculate Chi-square
# Grand total
grand_total = 0
row_totals = {}
col_totals = {'Yes': 0, 'No': 0}

for hist_type, val in filtered_counts.items():
    row_sum = val['Yes'] + val['No']
    row_totals[hist_type] = row_sum
    grand_total += row_sum
    col_totals['Yes'] += val['Yes']
    col_totals['No'] += val['No']

chi2_stat = 0.0

if grand_total > 0:
    for hist_type, val in filtered_counts.items():
        # Yes
        O_yes = val['Yes']
        E_yes = (row_totals[hist_type] * col_totals['Yes']) / grand_total
        if E_yes > 0:
            chi2_stat += ((O_yes - E_yes) ** 2) / E_yes

        # No
        O_no = val['No']
        E_no = (row_totals[hist_type] * col_totals['No']) / grand_total
        if E_no > 0:
            chi2_stat += ((O_no - E_no) ** 2) / E_no

print("__RESULT__:")
print(json.dumps({
    "chi_square_statistic": chi2_stat,
    "contingency_table": filtered_counts,
    "excluded_types": excluded_types,
    "grand_total": grand_total
}))

